INSERT INTO `company_settings` VALUES (1,'Astreablue Intelligence Inc.','20th Floor Unit 2004 Philippine AXA Life Centre 1286 Sen. Gil Puyat Avenue, Makati CIty, Philippines','','hris@astreablue.com','(632) 467-9867','data:image/png;base64,','Astreablue Intelligence Inc. is committed to maintaining a professional, inclusive, and productive workplace. All employees are expected to adhere to the highest standards of conduct, integrity, and performance.\n\nWorking Hours: Regular working hours are Monday to Friday, 8:00 AM to 5:00 PM, with a one-hour lunch break. Flexible arrangements may be approved by the department head.\n\nAttendance: Punctuality is required. Tardiness and absences must be reported to the immediate supervisor as soon as possible. Habitual tardiness or unexcused absences are subject to disciplinary action.\n\nDress Code: Employees are expected to dress professionally and appropriately for their role and work environment.\n\nConfidentiality: All employees must maintain strict confidentiality of company information, client data, and internal processes.','2026-06-29 06:58:09','Software Development','hris.astreablue.com','','2026','data:image/png;base64,','data:image/png;base64,','data:image/png;base64,','Astreablue Intelligence Inc. provides the following leave entitlements in accordance with Philippine labor law and company policy:\n\nVacation Leave (VL): 15 days per year, accrued monthly. Unused VL may be converted to cash at year-end up to a maximum of 5 days.\n\nSick Leave (SL): 15 days per year. A medical certificate is required for absences exceeding 2 consecutive days.\n\nMaternity Leave: 105 days paid (as per RA 11210) for female employees who have rendered at least 6 months of service.\n\nPaternity Leave: 7 days paid for married male employees upon the birth of their legitimate child.\n\nSolo Parent Leave: 7 days per year for solo parents with a valid Solo Parent ID.\n\nLeave Filing: All leave requests must be filed through the HR system at least 3 days in advance for planned absences. Emergency leave must be reported within 24 hours.','Overtime work shall only be performed upon prior written approval of the department head and HR. Unauthorized overtime will not be compensated.\n\nOvertime Rate: Work performed beyond regular hours is compensated at 125% of the hourly rate on regular days, 130% on rest days, and 200% on regular holidays, in accordance with the Philippine Labor Code.\n\nNight Differential: Work performed between 10:00 PM and 6:00 AM is entitled to an additional 10% of the hourly rate.\n\nOvertime Filing: All overtime requests must be submitted via the HR system before the scheduled overtime work. Post-work overtime claims will not be honored without prior approval.','Astreablue Intelligence Inc. expects all employees to conduct themselves in a manner that reflects the company\'s core values of integrity, excellence, and respect.\n\n1. Professionalism: Treat all colleagues, clients, and partners with respect and courtesy at all times.\n\n2. Conflict of Interest: Employees must disclose any personal or financial interest that may conflict with their duties. Outside employment must be approved by HR.\n\n3. Anti-Harassment: The company maintains a zero-tolerance policy for workplace harassment, bullying, and discrimination of any kind.\n\n4. Use of Company Resources: Company equipment, systems, and resources are for business use only. Personal use must be minimal and must not interfere with work.\n\n5. Social Media: Employees must not post confidential company information or make statements that could damage the company\'s reputation on any social media platform.\n\n6. Disciplinary Action: Violations of this code may result in verbal warning, written warning, suspension, or termination depending on the severity and frequency of the offense.','Astreablue Intelligence Inc. is committed to protecting the privacy and confidentiality of all employee personal data in compliance with the Data Privacy Act of 2012 (Republic Act No. 10173).\n\nData Collected: The company collects personal information necessary for employment purposes, including but not limited to: name, address, government IDs (SSS, PhilHealth, Pag-IBIG, TIN), contact details, payroll information, and attendance records.\n\nPurpose of Processing: Employee data is processed solely for payroll administration, benefits management, compliance with government requirements, and internal HR operations.\n\nData Access: Access to employee personal data is limited to authorized HR and payroll personnel only. Data is not shared with third parties except as required by law.\n\nData Security: The company implements appropriate technical and organizational measures to protect employee data from unauthorized access, disclosure, or loss.\n\nEmployee Rights: Employees have the right to access, correct, or request erasure of their personal data. Requests may be submitted in writing to the HR department.\n\nData Retention: Employee records are retained for a minimum of 10 years after the end of employment, as required by Philippine labor regulations.','','','','','','Private','','');
/*!40000 ALTER TABLE `company_settings` ENABLE KEYS */;
UNLOCK TABLES;

